/* 수식은 기본 트리거 확인용 */
BBU1 = BBandsUp(20,2); BBU2 = BBandsUp(60,2);
A1 = (C(2)>BBU1(2) || C(1)>BBU1(1) || C>BBU1);
A2 = (C(2)>BBU2(2) || C(1)>BBU2(1) || C>BBU2);
A3 = O(2)<C(2) || C(3)<C(2);
A4 = O(1)<=C(1) || C(2)<C(1);
A5 = O>C;
B = A1 && A2 && A3 && A4 && A5;
TargetLine = ValueWhen(1, B, O);
CrossUp(C, TargetLine) && V > avg(V, 20) * 1.5 && C > avg(C, 200)
